namespace sv_7be2fc047a804f81a0f9f6530635f69c.Models;

public class WizardData
{
    // Step 1: Personal Info
    public string Name { get; set; } = "";
    public string Email { get; set; } = "";

    // Step 2: Experience
    public List<JobEntry> JobHistory { get; set; } = [];

    // Step 3: References
    public List<ReferenceContact> References { get; set; } = [];

    public bool IsStep1Complete => !string.IsNullOrWhiteSpace(Name) && !string.IsNullOrWhiteSpace(Email);
    public bool IsStep2Complete => JobHistory.Count > 0;
    public bool IsStep3Complete => References.Count > 0;

    public int CompletedSteps
    {
        get
        {
            int count = 0;
            if (IsStep1Complete) count++;
            if (IsStep2Complete) count++;
            if (IsStep3Complete) count++;
            return count;
        }
    }
}

public class JobEntry
{
    public string Company { get; set; } = "";
    public string Title { get; set; } = "";
    public string Years { get; set; } = "";
}

public class ReferenceContact
{
    public string Name { get; set; } = "";
    public string Email { get; set; } = "";
    public string Relationship { get; set; } = "";
}

using System.Collections.Concurrent;
using sv_7be2fc047a804f81a0f9f6530635f69c.Models;

namespace sv_7be2fc047a804f81a0f9f6530635f69c.Services;

/// <summary>
/// Singleton server-side store for wizard data, keyed by session ID.
/// Accessible from both static SSR (layout) and interactive server components (pages).
/// </summary>
public class WizardStateStore
{
    private readonly ConcurrentDictionary<string, WizardData> _store = new();

    public WizardData GetOrCreate(string sessionId)
    {
        return _store.GetOrAdd(sessionId, _ => new WizardData());
    }

    public void Remove(string sessionId)
    {
        _store.TryRemove(sessionId, out _);
    }
}

