arguments.file_text:
@inherits LayoutComponentBase
@inject IHttpContextAccessor HttpContextAccessor
@inject sv_7be2fc047a804f81a0f9f6530635f69c.Services.WizardStateStore Store

@{
    var path = HttpContextAccessor.HttpContext?.Request.Path.Value ?? "";
    int currentStep = path switch
    {
        "/apply/experience" => 2,
        "/apply/references" => 3,
        "/apply/review" => 4,
        _ => 1
    };

    var sessionId = HttpContextAccessor.HttpContext?.Request.Cookies["WizardSessionId"];
    var data = sessionId is not null ? Store.GetOrCreate(sessionId) : null;
}

<div class="page">
    <div class="sidebar">
        <NavMenu />
    </div>

    <main>
        <div class="wizard-progress px-4 py-3">
            <h5 class="mb-2">Job Application — Step @currentStep of 4</h5>
            <div class="d-flex gap-2 mb-2">
                @for (int i = 1; i <= 4; i++)
                {
                    var step = i;
                    var isActive = step == currentStep;
                    var isCompleted = data is not null && step switch
                    {
                        1 => data.IsStep1Complete,
                        2 => data.IsStep2Complete,
                        3 => data.IsStep3Complete,
                        4 => data.IsStep1Complete && data.IsStep2Complete && data.IsStep3Complete,
                        _ => false
                    };

                    <a href="@StepUrl(step)"
                       class="wizard-step @(isActive ? "active" : "") @(isCompleted ? "completed" : "")">
                        <span class="step-number">@step</span>
                        <span class="step-label">@StepLabel(step)</span>
                    </a>
                }
            </div>
            <div class="progress" style="height: 6px;">
                <div class="progress-bar" role="progressbar"
                     style="width: @(currentStep * 25)%"></div>
            </div>
        </div>

        <article class="content px-4">
            @Body
        </article>
    </main>
</div>

<div id="blazor-error-ui" data-nosnippet>
    An unhandled error has occurred.
    <a href="." class="reload">Reload</a>
    <span class="dismiss">🗙</span>
</div>

@code {
    private static string StepUrl(int step) => step switch
    {
        1 => "/apply/personal-info",
        2 => "/apply/experience",
        3 => "/apply/references",
        4 => "/apply/review",
        _ => "/apply/personal-info"
    };

    private static string StepLabel(int step) => step switch
    {
        1 => "Personal Info",
        2 => "Experience",
        3 => "References",
        4 => "Review",
        _ => ""
    };
}

.wizard-progress {
    background-color: #f8f9fa;
    border-bottom: 1px solid #dee2e6;
}

.wizard-step {
    display: flex;
    align-items: center;
    gap: 0.4rem;
    padding: 0.35rem 0.75rem;
    border-radius: 1rem;
    text-decoration: none;
    font-size: 0.85rem;
    color: #6c757d;
    background: #e9ecef;
    transition: all 0.15s;
}

.wizard-step:hover {
    background: #dee2e6;
    color: #495057;
}

.wizard-step.active {
    background: #0d6efd;
    color: #fff;
    font-weight: 600;
}

.wizard-step.completed:not(.active) {
    background: #198754;
    color: #fff;
}

.step-number {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: 1.4rem;
    height: 1.4rem;
    border-radius: 50%;
    background: rgba(255,255,255,0.25);
    font-size: 0.75rem;
    font-weight: 700;
}

.step-label {
    white-space: nowrap;
}

