@page "/apply/experience"
@layout ApplyLayout
@rendermode InteractiveServer

@inject NavigationManager Nav
@inject sv_7be2fc047a804f81a0f9f6530635f69c.Services.WizardStateStore Store
@inject IHttpContextAccessor HttpContextAccessor
@inject PersistentComponentState PersistentState

@using sv_7be2fc047a804f81a0f9f6530635f69c.Models

<PageTitle>Experience — Apply</PageTitle>

<h3>Work Experience</h3>

@if (_entries.Count > 0)
{
    <table class="table table-sm mb-3">
        <thead>
            <tr><th>Company</th><th>Title</th><th>Years</th><th></th></tr>
        </thead>
        <tbody>
            @foreach (var (entry, idx) in _entries.Select((e, i) => (e, i)))
            {
                <tr>
                    <td>@entry.Company</td>
                    <td>@entry.Title</td>
                    <td>@entry.Years</td>
                    <td><button class="btn btn-sm btn-outline-danger" @onclick="() => Remove(idx)">✕</button></td>
                </tr>
            }
        </tbody>
    </table>
}

<div class="card p-3 mb-3">
    <h6>Add Job</h6>
    <div class="row g-2">
        <div class="col-md-4">
            <input class="form-control" placeholder="Company" @bind="_newEntry.Company" />
        </div>
        <div class="col-md-4">
            <input class="form-control" placeholder="Title" @bind="_newEntry.Title" />
        </div>
        <div class="col-md-2">
            <input class="form-control" placeholder="Years" @bind="_newEntry.Years" />
        </div>
        <div class="col-md-2">
            <button class="btn btn-success w-100" @onclick="AddEntry">Add</button>
        </div>
    </div>
</div>

<div class="d-flex justify-content-between">
    <button class="btn btn-outline-secondary" @onclick="Back">← Back</button>
    <button class="btn btn-primary" @onclick="Next">Next →</button>
</div>

@code {
    private List<JobEntry> _entries = [];
    private JobEntry _newEntry = new();
    private string _sessionId = "";
    private PersistingComponentStateSubscription _sub;

    protected override void OnInitialized()
    {
        _sub = PersistentState.RegisterOnPersisting(() =>
        {
            PersistentState.PersistAsJson("wizardSessionId", _sessionId);
            return Task.CompletedTask;
        });

        if (!PersistentState.TryTakeFromJson<string>("wizardSessionId", out var restored))
        {
            var ctx = HttpContextAccessor.HttpContext!;
            _sessionId = ctx.Request.Cookies["WizardSessionId"] ?? "";
            if (string.IsNullOrEmpty(_sessionId))
            {
                _sessionId = Guid.NewGuid().ToString();
                ctx.Response.Cookies.Append("WizardSessionId", _sessionId, new CookieOptions
                {
                    HttpOnly = true, SameSite = SameSiteMode.Strict, MaxAge = TimeSpan.FromHours(4)
                });
            }
        }
        else
        {
            _sessionId = restored!;
        }

        var data = Store.GetOrCreate(_sessionId);
        _entries = data.JobHistory.Select(j => new JobEntry
        {
            Company = j.Company, Title = j.Title, Years = j.Years
        }).ToList();
    }

    private void AddEntry()
    {
        if (string.IsNullOrWhiteSpace(_newEntry.Company)) return;
        _entries.Add(_newEntry);
        _newEntry = new();
        SaveToStore();
    }

    private void Remove(int index)
    {
        _entries.RemoveAt(index);
        SaveToStore();
    }

    private void SaveToStore()
    {
        var data = Store.GetOrCreate(_sessionId);
        data.JobHistory = _entries.Select(e => new JobEntry
        {
            Company = e.Company, Title = e.Title, Years = e.Years
        }).ToList();
    }

    private void Back()
    {
        SaveToStore();
        Nav.NavigateTo("/apply/personal-info");
    }

    private void Next()
    {
        SaveToStore();
        Nav.NavigateTo("/apply/references");
    }

    public void Dispose() => _sub.Dispose();
}

