@page "/apply/review"
@layout ApplyLayout
@rendermode InteractiveServer

@inject NavigationManager Nav
@inject sv_7be2fc047a804f81a0f9f6530635f69c.Services.WizardStateStore Store
@inject IHttpContextAccessor HttpContextAccessor
@inject PersistentComponentState PersistentState

@using sv_7be2fc047a804f81a0f9f6530635f69c.Models

<PageTitle>Review — Apply</PageTitle>

<h3>Review Your Application</h3>

@if (_data is not null)
{
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Personal Information</strong>
            <a href="/apply/personal-info" class="btn btn-sm btn-outline-primary">Edit</a>
        </div>
        <div class="card-body">
            <p><strong>Name:</strong> @_data.Name</p>
            <p class="mb-0"><strong>Email:</strong> @_data.Email</p>
        </div>
    </div>

    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Work Experience</strong>
            <a href="/apply/experience" class="btn btn-sm btn-outline-primary">Edit</a>
        </div>
        <div class="card-body">
            @if (_data.JobHistory.Count == 0)
            {
                <p class="text-muted mb-0">No entries added.</p>
            }
            else
            {
                <table class="table table-sm mb-0">
                    <thead><tr><th>Company</th><th>Title</th><th>Years</th></tr></thead>
                    <tbody>
                        @foreach (var job in _data.JobHistory)
                        {
                            <tr><td>@job.Company</td><td>@job.Title</td><td>@job.Years</td></tr>
                        }
                    </tbody>
                </table>
            }
        </div>
    </div>

    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>References</strong>
            <a href="/apply/references" class="btn btn-sm btn-outline-primary">Edit</a>
        </div>
        <div class="card-body">
            @if (_data.References.Count == 0)
            {
                <p class="text-muted mb-0">No references added.</p>
            }
            else
            {
                <table class="table table-sm mb-0">
                    <thead><tr><th>Name</th><th>Email</th><th>Relationship</th></tr></thead>
                    <tbody>
                        @foreach (var r in _data.References)
                        {
                            <tr><td>@r.Name</td><td>@r.Email</td><td>@r.Relationship</td></tr>
                        }
                    </tbody>
                </table>
            }
        </div>
    </div>

    <div class="d-flex justify-content-between">
        <button class="btn btn-outline-secondary" @onclick="Back">← Back</button>
        <button class="btn btn-success" @onclick="Submit">Submit Application</button>
    </div>

    @if (_submitted)
    {
        <div class="alert alert-success mt-3">
            Your application has been submitted successfully!
        </div>
    }
}

@code {
    private WizardData? _data;
    private string _sessionId = "";
    private bool _submitted;
    private PersistingComponentStateSubscription _sub;

    protected override void OnInitialized()
    {
        _sub = PersistentState.RegisterOnPersisting(() =>
        {
            PersistentState.PersistAsJson("wizardSessionId", _sessionId);
            return Task.CompletedTask;
        });

        if (!PersistentState.TryTakeFromJson<string>("wizardSessionId", out var restored))
        {
            var ctx = HttpContextAccessor.HttpContext!;
            _sessionId = ctx.Request.Cookies["WizardSessionId"] ?? "";
        }
        else
        {
            _sessionId = restored!;
        }

        if (!string.IsNullOrEmpty(_sessionId))
        {
            _data = Store.GetOrCreate(_sessionId);
        }
    }

    private void Back() => Nav.NavigateTo("/apply/references");

    private void Submit()
    {
        _submitted = true;
    }

    public void Dispose() => _sub.Dispose();
}

